func fallback(value string) string {
	if value == "" {
		return "none"
	}

	return value
}

func tagCountLabel(tags []issueapp.TagView) string {
	if len(tags) == 1 {
		return "1 tag"
	}

	return fmt.Sprint(len(tags)) + " tags"
}

func commentCountLabel(comments []issueapp.CommentView) string {
	if len(comments) == 1 {
		return "1 comment"
	}

	return fmt.Sprint(len(comments)) + " comments"
}

func userReportCountLabel(reports userreportapp.IssueReportsView) string {
	if len(reports.Items) == 1 {
		return "1 report"
	}

	return fmt.Sprint(len(reports.Items)) + " reports"
}

func statusFilterClass(active string, status string) string {
	if active == status {
		return "chip-filter is-active"
	}

	return "chip-filter"
}

func issueRowClass(level string) string {
	value := strings.ToLower(level)
	if value == "fatal" {
		return "irow lv-fatal"
	}

	if value == "warning" || value == "warn" {
		return "irow lv-warn"
	}

	if value == "info" {
		return "irow lv-info"
	}

	if value == "debug" {
		return "irow lv-debug"
	}

	return "irow lv-error"
}

func levelChipClass(level string) string {
	value := strings.ToLower(level)
	if value == "fatal" {
		return "chip chip--fatal"
	}

	if value == "warning" || value == "warn" {
		return "chip chip--warn"
	}

	if value == "info" {
		return "chip chip--info"
	}

	if value == "debug" {
		return "chip chip--debug"
	}

	return "chip chip--error"
}

